            sqlString += "tblSong.Artist_ID, tblSong.Album_ID, tblSong.Song_Length, tblSong.Song_Pop ,tblSong.Song_Clip ";
            sqlString += "FROM tblSong inner join tblArtist on tblArtist.Artist_ID = tblSong.Artist_ID ";
            sqlString += "inner join tblAlbum on tblAlbum.Album_ID = tblSong.Album_ID ";
            sqlString += "WHERE Song_Genre='" + Genre + "'";

            return GetDataTable(sqlString, Genre);
        }

        /// <summary>
        /// return a data table with Song_Name and Song_ID, where the song name matches the input string
        /// </summary>
        /// <param name="Genre"></param>
        /// <returns></returns>
        public static DataTable SongNameLike(string input)
        {
            string sqlString = "SELECT tblSong.Song_ID, tblSong.Song_Name ";
            sqlString += "FROM tblSong ";
            sqlString += "WHERE tblSong.Song_Name LIKE '%";
            sqlString += input;
            sqlString += "%' ORDER BY tblSong.Song_Pop DESC";
            return GetDataTable(sqlString, input);
        }

        public static int GetSongNextID()
        {
            DataTable dt = GetDataTable("SELECT MAX(Song_ID) FROM tblSong", "tblmaxsong");
            if (dt.Rows.Count == 0)
                return 1;
            else
                return int.Parse(dt.Rows[0][0].ToString()) + 1;
        }

        public static DataTable LastSongsAdded(int number)
        {
            string sqlString = "SELECT TOP " + number.ToString() + " tblSong.Song_ID, tblSong.Song_Name, tblArtist.Artist_Name, ";
            sqlString += "tblSong.Artist_ID, tblSong.Song_Genre  ";
            sqlString += "FROM tblSong inner join tblArtist on tblArtist.Artist_ID = tblSong.Artist_ID ";
            sqlString += "ORDER BY tblSong.Song_ID DESC";
            DataTable dt = GetDataTable(sqlString, "tblSong");
            return dt;
        }

        public static DataTable RandomSongs(int number)
        {
            string SS = "SELECT TOP " + number.ToString() + " tblSong.Song_ID, tblSong.Song_Name, tblArtist.Artist_Name, tblSong.Artist_ID, tblSong.Song_Genre ";
            SS += " FROM tblSong inner join tblArtist on tblArtist.Artist_ID = tblSong.Artist_ID ORDER By NEWID()";
            return GetDataTable(SS, "NewAlbums");
        }

    }
