        {
            if (FullConnected("INSERT INTO tblUserArtistsList(User_ID, Artist_ID) VALUES('" + User_ID + "','" + Artist_ID + "')") == 1)
            {
                DAL.tblArtist.AddArtistPOP(Artist_ID, 1);
                return 1;
            }
            return 0;
        }

        public static int DeleteUserArtistsList(int User_ID, int Artist_ID)
        {
            if (FullConnected("DELETE FROM tblUserArtistsList WHERE User_ID='" + User_ID + "' AND Artist_ID='" + Artist_ID + "'") == 1)
            {
                DAL.tblArtist.AddArtistPOP(Artist_ID, -1);
                return 1;
