    /*********************************** REQUEST SONG PAGE ************************************************************************************/

    [WebMethod]
    public int InsertRequestSong(
         string Song_Name,
         int Album_ID,
         string Album_Name,
         int Artist_ID,
         string Artist_Name,
         string Song_Lyrics,
         string Song_Clip,
         int Min, int Sec,
         string Song_Genre,
         string Song_Pic,
         string Song_Rtype
         )
    {
        DateTime dt = new DateTime();
        dt.AddMinutes(Min);
        dt.AddSeconds(Sec);
        return DAL.tblRequestSong.InsertRequestSong(DAL.tblRequestSong.GetRequestSongNextID(), Song_Name, Album_ID, Album_Name, Artist_ID,
            Artist_Name, Song_Lyrics, Song_Clip, dt.ToString(), Song_Genre, Song_Pic, Song_Rtype);
    }

